import React, { useState, useEffect, useRef } from 'react'
import { trackPromise } from 'react-promise-tracker'
import { Link } from 'react-router-dom'
import axios from 'axios'
import {
  CCardHeader,
  CCard,
  CCardBody,
  CTable,
  CTableHead,
  CTableRow,
  CTableHeaderCell,
  CTableBody,
  CTableDataCell,
  CBadge,
  CButton,
  CModal,
  CForm,
  CModalHeader,
  CModalTitle,
  CModalBody,
  CInputGroup,
  CInputGroupText,
  CFormInput,
  CModalFooter,
  CSpinner,
  CToaster,
  CFormFloating,
  CFormLabel,
  CAlert,
} from '@coreui/react'
import CIcon from '@coreui/icons-react'
import { getUser } from 'src/utils/Auth'
import LoadingIndicator from 'src/utils/LoadingIndicator'
import Notify from 'src/utils/Notify'

const Applications = () => {
  const [apps, setApps] = useState([])
  const [edit, setEdit] = useState(false)
  const [update, setUpdate] = useState(false)
  const [validated, setValidated] = useState(false)
  const [appid, setAppid] = useState(null)
  const [fields, setFields] = useState({})
  const [updatefields, setUpdateFields] = useState([])
  const [error, setError] = useState(false)
  const [toast, addToast] = useState(0)
  const [message, setMessage] = useState(null)
  const toaster = useRef()
  const user = getUser()

  useEffect(() => {
    getAppStat()
  }, [])

  useEffect(() => {
    if (message) addToast(notify)
  }, [message])

  const notify = <Notify error={error} message={message} />

  const getAppStat = async () => {
    const resFromServer = await fetchStat()
    resFromServer ? setApps(resFromServer) : setApps(null)
  }

  const fetchStat = async () => {
    const res = await trackPromise(
      fetch(
        `https://records.run.edu.ng/api/app/my_applications?userid=${user.id}&matno=${user.matric_number}`,
      ),
    )
    const data = await res.json()
    return data
  }

  const checkToken = (id) => {
    setEdit(!edit)
    setAppid(id)
  }

  const validateToken = (event) => {
    event.preventDefault()
    const form = event.currentTarget
    if (form.checkValidity() === false) {
      event.stopPropagation()
      return
    }
    setValidated(true)
    setMessage(null)
    setError(null)
    axios
      .post('https://records.run.edu.ng/api/app/edit_app_and_verify_editpin', {
        userid: user.id,
        matno: user.matric_number,
        token: fields.token,
        appid: appid,
        requestType: 'check_token',
      })
      .then(function (response) {
        setUpdateFields(response.data.data)
        setValidated(false)
        console.log(response.data.data)
        console.log(updatefields)
        setMessage(response.data.message)
        setEdit(false)
        setUpdate(true)
      })
      .catch((err) => {
        setValidated(false)
        setError(true)
        if (err.response) {
          setMessage(err.response.data.message)
        } else {
          setMessage('Network Error!')
        }
      })
  }

  const handleEditForm = (event) => {
    const form = event.currentTarget
    if (form.checkValidity() === false) {
      event.stopPropagation()
      return
    }
    setValidated(true)
    setMessage(null)
    setError(null)
    const formData = new FormData()
    const config = {
      headers: {
        'content-type': 'multipart/form-data',
      },
    }

    Object.keys(fields).map((i) => {
      formData.append([i], fields[i])
      console.log([i])
      return true
    })

    formData.append('userid', user.id)
    formData.append('matno', user.matric_number)
    formData.append('appid', appid)
    formData.append('requestType', 'update')
    axios
      .post('https://records.run.edu.ng/api/app/edit_app_and_verify_editpin', formData, config)
      .then(function (response) {
        getAppStat()
        setValidated(false)
        console.log(response)
        setMessage(response.data.message)
        setUpdate(false)
      })
      .catch((err) => {
        setValidated(false)
        setError(true)
        if (err.response) {
          setMessage(err.response.data.message)
        } else {
          setMessage('Network Error!')
        }
      })
  }

  const handleEditChange = (e) => {
    const { id, value } = e.target
    setFields((prevState) => ({
      ...prevState,
      [id]: value,
    }))
  }

  const onFileChange = (e) => {
    console.log(e.target.files[0])
    setFields((prevState) => ({
      ...prevState,
      certificate: e.target.files[0],
    }))
  }

  const keys = Object.keys(updatefields)
  const toUpdate = keys.map((key, index) => {
    //console.log(`${key}: ${updatefields[key]}`)
    return (
      <CFormFloating className="mb-3" key={index}>
        <CFormInput
          type={key === 'certificate' ? 'file' : 'text'}
          id={key}
          onChange={key === 'certificate' ? onFileChange : handleEditChange}
          required
        />
        <CFormLabel htmlFor={key}>
          {key} <span style={{ color: 'red' }}>({updatefields[key]})</span>
        </CFormLabel>
      </CFormFloating>
    )
  })

  return (
    <>
      <CCard className="mb-4">
        <CCardHeader>
          <Link to="/application/form">Create New Application</Link>
        </CCardHeader>
        <CCardBody>
          <CTable responsive>
            <CTableHead color="dark">
              <CTableRow>
                <CTableHeaderCell scope="col">#</CTableHeaderCell>
                <CTableHeaderCell scope="col">Recipient</CTableHeaderCell>
                <CTableHeaderCell scope="col">Transcript Type</CTableHeaderCell>
                <CTableHeaderCell scope="col">Date</CTableHeaderCell>
                <CTableHeaderCell scope="col">Status</CTableHeaderCell>
                <CTableHeaderCell scope="col">Action</CTableHeaderCell>
              </CTableRow>
            </CTableHead>
            {apps ? (
              <CTableBody>
                {apps.map((item, index) => (
                  <CTableRow key={index}>
                    <CTableHeaderCell scope="row">{index + 1}</CTableHeaderCell>
                    <CTableDataCell>{item.recipient}</CTableDataCell>
                    <CTableDataCell>{item.transcript_type}</CTableDataCell>
                    <CTableDataCell>{new Date(item.created_at).toDateString()}</CTableDataCell>
                    <CTableDataCell>
                      {item.app_status === 'APPROVED' ? (
                        <CBadge color="success" shape="rounded-pill">
                          {item.app_status}
                        </CBadge>
                      ) : (
                        <CBadge color="secondary" shape="rounded-pill">
                          {item.app_status}
                        </CBadge>
                      )}
                    </CTableDataCell>
                    <CTableDataCell>
                      <CButton
                        type="button"
                        color="info"
                        disabled={item.app_status === 'FAILED' ? false : true}
                        onClick={() => checkToken(item.application_id)}
                      >
                        Edit
                      </CButton>
                    </CTableDataCell>
                  </CTableRow>
                ))}
              </CTableBody>
            ) : (
              <LoadingIndicator />
            )}
            <LoadingIndicator />
          </CTable>
        </CCardBody>
      </CCard>

      <CModal visible={edit} onClose={() => setEdit(false)}>
        <CForm noValidate validated={validated} onSubmit={validateToken}>
          <CModalHeader onClose={() => setEdit(false)}>
            <CModalTitle>Edit Application</CModalTitle>
          </CModalHeader>
          <CModalBody>
            <CInputGroup className="mb-3">
              <CInputGroupText>
                <CIcon />
              </CInputGroupText>
              <CFormInput
                type="text"
                id="token"
                onChange={handleEditChange}
                placeholder="Enter your token"
                required
              />
            </CInputGroup>
          </CModalBody>
          <CModalFooter>
            <CButton color="secondary" onClick={() => setEdit(false)}>
              Close
            </CButton>
            <CButton disabled={validated} type="submit" color="primary">
              {validated && (
                <CSpinner
                  component="span"
                  size="sm"
                  color="light"
                  variant="grow"
                  aria-hidden="true"
                />
              )}
              Send
            </CButton>
          </CModalFooter>
        </CForm>
      </CModal>

      <CModal visible={update} onClose={() => setUpdate(false)}>
        <CForm noValidate validated={validated} onSubmit={handleEditForm}>
          <CModalHeader onClose={() => setUpdate(false)}>
            <CModalTitle>Edit Application</CModalTitle>
          </CModalHeader>
          <CModalBody>
            <CAlert color="danger">Note: Corrections are highlighted in red</CAlert>
            {toUpdate}
          </CModalBody>
          <CModalFooter>
            <CButton color="secondary" onClick={() => setUpdate(false)}>
              Close
            </CButton>
            <CButton disabled={validated} type="submit" color="primary">
              {validated && (
                <CSpinner
                  component="span"
                  size="sm"
                  color="light"
                  variant="grow"
                  aria-hidden="true"
                />
              )}
              Send
            </CButton>
          </CModalFooter>
        </CForm>
      </CModal>
      <CToaster ref={toaster} push={toast} placement="top-end" />
    </>
  )
}

export default Applications
